from sqlalchemy import create_engine, Column, Integer, String, ForeignKey, Float
from sqlalchemy.orm import sessionmaker, relationship
from sqlalchemy.ext.declarative import declarative_base

Base = declarative_base()

class Bicycle(Base):
    __tablename__ = 'bicycles'

    id = Column(Integer, primary_key=True)
    model = Column(String)
    brand = Column(String)
    price = Column(Float)
    components = relationship('Component', backref='bicycle')
    accessories = relationship('Accessory', backref='bicycle')

class Component(Base):
    __tablename__ = 'components'

    id = Column(Integer, primary_key=True)
    name = Column(String)
    price = Column(Float)
    bicycle_id = Column(Integer, ForeignKey('bicycles.id'))

class Accessory(Base):
    __tablename__ = 'accessories'

    id = Column(Integer, primary_key=True)
    name = Column(String)
    price = Column(Float)
    bicycle_id = Column(Integer, ForeignKey('bicycles.id'))

def connect_to_db(db_url):
    engine = create_engine(db_url)
    Session = sessionmaker(bind=engine)
    return Session()

def add_bicycle(session, model, brand, price):
    bicycle = Bicycle(model=model, brand=brand, price=price)
    session.add(bicycle)
    session.commit()
    return bicycle

def add_component(session, name, price, bicycle):
    component = Component(name=name, price=price, bicycle=bicycle)
    session.add(component)
    session.commit()
    return component

def add_accessory(session, name, price, bicycle):
    accessory = Accessory(name=name, price=price, bicycle=bicycle)
    session.add(accessory)
    session.commit()
    return accessory

def get_bicycle(session, bicycle_id):
    return session.query(Bicycle).get(bicycle_id)

def get_components(session, bicycle):
    return session.query(Component).filter_by(bicycle=bicycle).all()

def get_accessories(session, bicycle):
    return session.query(Accessory).filter_by(bicycle=bicycle).all()

def update_bicycle(session, bicycle, model=None, brand=None, price=None):
    if model:
        bicycle.model = model
    if brand:
        bicycle.brand = brand
    if price:
        bicycle.price = price
    session.commit()
    return bicycle

def delete_bicycle(session, bicycle):
    session.delete(bicycle)
    session.commit()

def search_bicycles(session, model=None, brand=None, min_price=None, max_price=None):
    query = session.query(Bicycle)
    if model:
        query = query.filter(Bicycle.model.like(f'%{model}%'))
    if brand:
        query = query.filter(Bicycle.brand.like(f'%{brand}%'))
    if min_price:
        query = query.filter(Bicycle.price >= min_price)
    if max_price:
        query = query.filter(Bicycle.price <= max_price)
    return query.all()
